use common::ToCanonicalBytes;
use cryptocore::{CryptoOperations, HashDigest, NodeId};
use hlc::Hlc;

/// The unique, deterministic, and permanent identifier of a CDU.
/// It is generated by hashing the combination of the creation HLC and the payload hash.
pub type CduId = HashDigest;

/// The immutable core content of a CDU.
/// It is an opaque vector of bytes. The creator of the CDU is responsible for
/// ensuring these bytes follow a meaningful, canonical format (e.g., UTF-8 JSON).
#[derive(Clone, Debug, Eq, PartialEq)]
pub struct Payload(Vec<u8>);

/// The context that evolves around the payload.
#[derive(Clone, Debug, Eq, PartialEq)]
pub struct Metadata {
    pub author_node: NodeId,
    pub context_refs: Vec<CduId>,
    // In a real implementation, this would be an enum.
    pub state: String,
    pub weight: u64,
    pub r_coordinate: i64,
    pub world_context: String,
}

/// The Causal Data Unit: the single, unified data model for all information.
#[derive(Clone, Debug, Eq, PartialEq)]
pub struct Cdu {
    pub id_hlc: CduId,
    pub payload: Payload,
    pub payload_hash: HashDigest,
    pub metadata: Metadata,
    // Signatures would be more complex in a real implementation.
    pub signatures: Vec<String>,
}

impl Cdu {
    /// Creates a new draft CDU. This is the entry point for all new information.
    pub fn new(author_node: NodeId, payload_content: Vec<u8>, creation_hlc: &Hlc) -> Self {
        let payload = Payload(payload_content);
        // The payload_hash is calculated directly on the raw bytes of the payload.
        let payload_hash = cryptocore::NodeKeys::hash(&payload.0);

        // Generate the unique, deterministic id_hlc.
        let id_hlc = Self::generate_id_hlc(creation_hlc, &payload_hash);

        Self {
            id_hlc,
            payload,
            payload_hash,
            metadata: Metadata {
                author_node,
                context_refs: Vec::new(),
                state: "draft".to_string(),
                weight: 1,
                r_coordinate: 0,
                world_context: "UserWorld".to_string(),
            },
            signatures: Vec::new(),
        }
    }

    /// Generates the deterministic CDU ID by hashing the HLC's canonical bytes
    /// and the payload hash together.
    fn generate_id_hlc(hlc: &Hlc, payload_hash: &HashDigest) -> CduId {
        let hlc_bytes = hlc
            .to_canonical_bytes()
            .expect("HLC serialization should not fail.");

        let mut combined = Vec::with_capacity(hlc_bytes.len() + payload_hash.len());
        combined.extend_from_slice(&hlc_bytes);
        combined.extend_from_slice(payload_hash);

        cryptocore::NodeKeys::hash(&combined)
    }
}

// --- Unit Tests ---
#[cfg(test)]
mod tests {
    use super::*;
    use cryptocore::{CryptoOperations, NodeKeys};

    #[test]
    fn test_cdu_creation_and_id_determinism() {
        let node_keys = NodeKeys::new();
        let mut hlc = Hlc::new(*node_keys.node_id());

        // Create the first timestamp and payload (as raw bytes).
        let t1 = hlc.new_timestamp();
        let payload1 = b"{\"message\":\"hello world\"}".to_vec();

        // Create the first CDU
        let cdu1 = Cdu::new(*node_keys.node_id(), payload1.clone(), &t1);

        // Re-create a CDU with the exact same inputs
        let cdu1_replica = Cdu::new(*node_keys.node_id(), payload1.clone(), &t1);

        assert_eq!(
            cdu1.id_hlc, cdu1_replica.id_hlc,
            "CDUs with identical creation HLC and payload must have the same ID."
        );

        // Create a second CDU with a different timestamp but same payload
        let t2 = hlc.new_timestamp();
        let cdu2 = Cdu::new(*node_keys.node_id(), payload1.clone(), &t2);

        assert_ne!(
            cdu1.id_hlc, cdu2.id_hlc,
            "CDUs with different creation HLCs should have different IDs."
        );

        // Create a third CDU with a different payload but same timestamp
        let payload3 = b"{\"message\":\"hello mars\"}".to_vec();
        let cdu3 = Cdu::new(*node_keys.node_id(), payload3, &t1);

        assert_ne!(
            cdu1.id_hlc, cdu3.id_hlc,
            "CDUs with different payloads should have different IDs."
        );
    }
}
